# Objective of this script is to fix some files generated by Pigeon because Pigeon does not support Custom Codecs.
# These transformations are tuned for Pigeon 26.x. If you bump Pigeon, re-verify every sed/perl below.

echo "Generate Pigeon Files."
(cd .. && dart run pigeon --input ./pigeons/messages.dart)
echo "Generation complete."
echo "First formatting."
melos format-ci > /dev/null
echo "Formatting complete."

# # Fix Java files
FILE_NAME="../../cloud_firestore/android/src/main/java/io/flutter/plugins/firebase/firestore/GeneratedAndroidFirebaseFirestore.java"
# Expose toList() so plugin code can serialize generated classes outside of the pigeon codec.
sed -i '' 's/ArrayList<Object> toList() {/public ArrayList<Object> toList() {/' "$FILE_NAME"
# Pigeon 26 emits a single `PigeonCodec` per file (was `FirebaseFirestoreHostApiCodec` in older versions).
# Swap its base class to the custom Firestore codec so Firestore types are encoded/decoded, and
# expose it publicly so the plugin can reuse it on EventChannel/MethodChannel instances (those
# must serialize Pigeon-generated types like `InternalDocumentSnapshot` emitted via stream handlers).
sed -i '' 's/private static class PigeonCodec extends StandardMessageCodec {/public static class PigeonCodec extends FlutterFirebaseFirestoreMessageCodec {/' "$FILE_NAME"

echo "Android modification complete."

# Fix iOS files
FILE_NAME="../../cloud_firestore/ios/cloud_firestore/Sources/cloud_firestore/FirestoreMessages.g.m"
sed -i '' '/#import "FirestoreMessages.g.h"/a\
#import "FLTFirebaseFirestoreReader.h"\
#import "FLTFirebaseFirestoreWriter.h"
' $FILE_NAME
# Pigeon 26 generates ObjC codec classes with a `null<FileName>PigeonCodec*` prefix when no
# ObjcOptions prefix is configured. Rename them to stable, readable names first.
sed -i '' 's/nullFirestoreMessagesPigeonCodecReaderWriter/FirebaseFirestoreHostApiCodecReaderWriter/g' $FILE_NAME
sed -i '' 's/nullFirestoreMessagesPigeonCodecReader/FirebaseFirestoreHostApiCodecReader/g' $FILE_NAME
sed -i '' 's/nullFirestoreMessagesPigeonCodecWriter/FirebaseFirestoreHostApiCodecWriter/g' $FILE_NAME
# Reparent the reader/writer onto our custom Firestore reader/writer so Firestore-specific
# types (Timestamp, GeoPoint, FieldValue, DocumentReference, FieldPath, ...) round-trip.
sed -i '' 's/@interface FirebaseFirestoreHostApiCodecReader : FlutterStandardReader/@interface FirebaseFirestoreHostApiCodecReader : FLTFirebaseFirestoreReader/' $FILE_NAME
sed -i '' 's/@interface FirebaseFirestoreHostApiCodecWriter : FlutterStandardWriter/@interface FirebaseFirestoreHostApiCodecWriter : FLTFirebaseFirestoreWriter/' $FILE_NAME

echo "iOS modification complete."

# Fix Windows files
FILE_NAME="../../cloud_firestore/windows/messages.g.h"
sed -i '' '/#include <string>/a\
#include "firestore_codec.h"
' $FILE_NAME
# Make FromEncodableList / ToEncodableList accessible from plugin code (they're used directly
# to serialize stream events). Pigeon 26 qualifies EncodableList with a leading `::`, hence the
# `::flutter::EncodableList` pattern below.
perl -i -0777 -pe 's|private:\n(\s+static InternalSnapshotMetadata FromEncodableList\(\n\s+const ::flutter::EncodableList& list\);\n\s+::flutter::EncodableList ToEncodableList\(\) const;)|\1\n\n private:|gs' $FILE_NAME
perl -0777 -i -pe 's/private:\n(\x20{2}static InternalDocumentSnapshot FromEncodableList\(\n\x20{6}const ::flutter::EncodableList& list\);\n\x20{2}::flutter::EncodableList ToEncodableList\(\) const;)/\1\n\n private:/gs' $FILE_NAME
perl -0777 -i -pe 's/private:\n(\x20{2}static InternalDocumentChange FromEncodableList\(\n\x20{6}const ::flutter::EncodableList& list\);\n\x20{2}::flutter::EncodableList ToEncodableList\(\) const;)/\1\n\n private:/gs' $FILE_NAME

# Pigeon 26 renamed the generated C++ codec class to `PigeonInternalCodecSerializer`. The Windows
# plugin code historically references `FirebaseFirestoreHostApiCodecSerializer`, so keep that
# stable name and reparent the class onto our custom Firestore codec.
sed -i '' 's/PigeonInternalCodecSerializer/FirebaseFirestoreHostApiCodecSerializer/g' $FILE_NAME
sed -i '' 's|: public ::flutter::StandardCodecSerializer {|: public cloud_firestore_windows::FirestoreCodec {|' $FILE_NAME

FILE_NAME="../../cloud_firestore/windows/messages.g.cpp"
sed -i '' 's/PigeonInternalCodecSerializer/FirebaseFirestoreHostApiCodecSerializer/g' $FILE_NAME
sed -i '' 's|::flutter::StandardCodecSerializer::WriteValue(value, stream)|::cloud_firestore_windows::FirestoreCodec::WriteValue(value, stream)|' $FILE_NAME
sed -i '' 's|::flutter::StandardCodecSerializer::ReadValueOfType(type, stream)|::cloud_firestore_windows::FirestoreCodec::ReadValueOfType(type, stream)|' $FILE_NAME

# Pigeon 26 no longer auto-renames a C++ enum whose identifier collides with a method in the same
# scope. The `PersistenceCacheIndexManagerRequest` enum collides with the host API method of the
# same name, which fails to compile on MSVC. Rename every *usage* of the enum type (but keep the
# method name intact) by first renaming the identifier globally and then restoring call/method
# sites that are followed by `(`.
for FILE_NAME in "../../cloud_firestore/windows/messages.g.h" "../../cloud_firestore/windows/messages.g.cpp"; do
  sed -i '' 's/PersistenceCacheIndexManagerRequest/PersistenceCacheIndexManagerRequestEnum/g' $FILE_NAME
  sed -i '' 's/PersistenceCacheIndexManagerRequestEnum(/PersistenceCacheIndexManagerRequest(/g' $FILE_NAME
done

echo "Windows modification complete."

# Fix Dart files
FILE_NAME="../lib/src/pigeon/messages.pigeon.dart"
# Pigeon 26 no longer imports flutter/foundation.dart, so anchor on flutter/services.dart instead.
sed -i '' '/import '\''package:flutter\/services\.dart'\'';/i\
import '\''package:cloud_firestore_platform_interface/src/method_channel/utils/firestore_message_codec.dart'\'';
' $FILE_NAME
# Pigeon 26 renamed the private codec to `_PigeonCodec`. Swap its base class to our custom one.
sed -i '' 's/class _PigeonCodec extends StandardMessageCodec {/class _PigeonCodec extends FirestoreMessageCodec {/' $FILE_NAME
(cd .. && dart fix --apply > /dev/null)

FILE_NAME="../test/pigeon/test_api.dart"
sed -i '' -E 's/import '\''dart:typed_data'\'' show Float64List, Int32List, Int64List, Uint8List;/import '\''dart:typed_data'\'' show Uint8List;/' $FILE_NAME

echo "Dart modification complete."

echo "Final formatting."
melos format-ci > /dev/null
echo "Formatting complete."

echo "All modifications complete."
